| MCP:I7emSV | import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
| MCP:I7emSV | import org.springframework.security.config.http.SessionCreationPolicy;
| MCP:I7emSV | import org.springframework.security.core.context.SecurityContextHolder;
| MCP:I7emSV | import org.springframework.security.web.SecurityFilterChain;
| MCP:I7emSV | import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
| MCP:I7emSV | import org.springframework.security.web.authentication.logout.LogoutHandler;
| MCP:I7emSV | 
| MCP:I7emSV | import static com.tzesh.springtemplate.enumeration.auth.Permission.*;
| MCP:I7emSV | import static com.tzesh.springtemplate.enumeration.auth.Role.ADMIN;
| MCP:I7emSV | import static com.tzesh.springtemplate.enumeration.auth.Role.MANAGER;
| MCP:I7emSV | import static org.springframework.http.HttpMethod.*;
| MCP:I7emSV | 
| MCP:I7emSV | /**
| MCP:I7emSV |  * @author tzesh
| MCP:I7emSV |  */
| MCP:I7emSV | @Configuration
| MCP:I7emSV | @EnableWebSecurity
| MCP:I7emSV | @RequiredArgsConstructor
| MCP:I7emSV | @EnableMethodSecurity
| MCP:I7emSV | public class SecurityChain {
| MCP:I7emSV |     private final AuthenticationFilter jwtAuthFilter;
| MCP:I7emSV |     private final AuthenticationProvider authenticationProvider;
| MCP:I7emSV |     private final LogoutHandler logoutHandler;
| MCP:I7emSV |     private final AuthenticationEntryPoint jwtAuthEntryPoint;
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Defines the bean used to manage authentication
| MCP:I7emSV |      * @param http HttpSecurity
| MCP:I7emSV |      * @return SecurityFilterChain
| MCP:I7emSV |      * @throws Exception if the authentication manager cannot be created
| MCP:I7emSV |      */
| MCP:I7emSV |     @Bean
| MCP:I7emSV |     public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
| MCP:I7emSV |         http
| MCP:I7emSV |             .csrf(csrf -> csrf.disable())
| MCP:I7emSV |             .authorizeHttpRequests(auth -> auth
| MCP:I7emSV |                 .requestMatchers(
| MCP:I7emSV |                     "/auth/**",
| MCP:I7emSV |                     "/v3/api-docs/**",
| MCP:I7emSV |                     "/swagger-resources",
| MCP:I7emSV |                     "/swagger-resources/**",
| MCP:I7emSV |                     "/configuration/ui",
| MCP:I7emSV |                     "/configuration/security",
| MCP:I7emSV |                     "/swagger-ui/**",
| MCP:I7emSV |                     "/webjars/**",
| MCP:I7emSV |                     "/swagger-ui.html",
| MCP:I7emSV |                     "/actuator/**"
| MCP:I7emSV |                 ).permitAll()
| MCP:I7emSV |                 .requestMatchers("/management/**").hasAnyRole(ADMIN.name(), MANAGER.name())
| MCP:I7emSV |                 .requestMatchers(GET, "/management/**").hasAnyAuthority(ADMIN_READ.name(), MANAGER_READ.name())
| MCP:I7emSV |                 .requestMatchers(POST, "/management/**").hasAnyAuthority(ADMIN_CREATE.name(), MANAGER_CREATE.name())
| MCP:I7emSV |                 .requestMatchers(PUT, "/management/**").hasAnyAuthority(ADMIN_UPDATE.name(), MANAGER_UPDATE.name())
| MCP:I7emSV |                 .requestMatchers(PATCH, "/management/**").hasAnyAuthority(ADMIN_UPDATE.name(), MANAGER_UPDATE.name())
| MCP:I7emSV |                 .requestMatchers(DELETE, "/management/**").hasAnyAuthority(ADMIN_DELETE.name(), MANAGER_DELETE.name())
| MCP:I7emSV |                 .anyRequest().authenticated()
| MCP:I7emSV |             )
| MCP:I7emSV |             .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
| MCP:I7emSV |             .authenticationProvider(authenticationProvider)
| MCP:I7emSV |             .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class)
| MCP:I7emSV |             .logout(logout -> logout
| MCP:I7emSV |                 .logoutUrl("/auth/logout")
| MCP:I7emSV |                 .addLogoutHandler(logoutHandler)
| MCP:I7emSV |                 .logoutSuccessHandler((request, response, authentication) -> SecurityContextHolder.clearContext())
| MCP:I7emSV |             )
| MCP:I7emSV |             .exceptionHandling(exception -> exception.authenticationEntryPoint(jwtAuthEntryPoint));
| MCP:I7emSV |         return http.build();
| MCP:I7emSV |     }
| MCP:I7emSV | }

