| MCP:I7emSV | import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
| MCP:I7emSV | import org.springframework.security.core.context.SecurityContextHolder;
| MCP:I7emSV | import org.springframework.security.core.userdetails.UserDetails;
| MCP:I7emSV | import org.springframework.security.core.userdetails.UserDetailsService;
| MCP:I7emSV | import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
| MCP:I7emSV | import org.springframework.stereotype.Component;
| MCP:I7emSV | import org.springframework.web.filter.OncePerRequestFilter;
| MCP:I7emSV | 
| MCP:I7emSV | import java.io.IOException;
| MCP:I7emSV | 
| MCP:I7emSV | /**
| MCP:I7emSV |  * JWT Authentication Filter class for authenticating JWT tokens
| MCP:I7emSV |  * and setting the authentication in the Security Context
| MCP:I7emSV |  * @see OncePerRequestFilter
| MCP:I7emSV |  * @see JwtService
| MCP:I7emSV |  * @see UserDetailsService
| MCP:I7emSV |  * @see TokenRepository
| MCP:I7emSV |  * @author tzesh
| MCP:I7emSV |  */
| MCP:I7emSV | @Component
| MCP:I7emSV | @RequiredArgsConstructor
| MCP:I7emSV | public class AuthenticationFilter extends OncePerRequestFilter {
| MCP:I7emSV | 
| MCP:I7emSV |     private final JwtService jwtService;
| MCP:I7emSV |     private final UserDetailsService userDetailsService;
| MCP:I7emSV |     private final TokenRepository tokenRepository;
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Method that filters the requests and authenticates the user
| MCP:I7emSV |      * @param request request HttpServletRequest
| MCP:I7emSV |      * @param response response HttpServletResponse
| MCP:I7emSV |      * @param filterChain filterChain that contains the filters
| MCP:I7emSV |      * @throws ServletException if the servlet encounters difficulty
| MCP:I7emSV |      * @throws IOException if the servlet encounters difficulty
| MCP:I7emSV |      */
| MCP:I7emSV |     @Override
| MCP:I7emSV |     protected void doFilterInternal(
| MCP:I7emSV |             @NonNull HttpServletRequest request,
| MCP:I7emSV |             @NonNull HttpServletResponse response,
| MCP:I7emSV |             @NonNull FilterChain filterChain
| MCP:I7emSV |     ) throws ServletException, IOException {
| MCP:I7emSV |         // if the request is for authentication, skip the filter
| MCP:I7emSV |         if (request.getServletPath().contains("/api/v1/auth")) {
| MCP:I7emSV |             filterChain.doFilter(request, response);
| MCP:I7emSV |             return;
| MCP:I7emSV |         }
| MCP:I7emSV | 
| MCP:I7emSV |         // get the token from the request header
| MCP:I7emSV |         final String authHeader = request.getHeader("Authorization");
| MCP:I7emSV | 
| MCP:I7emSV |         // initialize the token and username
| MCP:I7emSV |         final String jwt;
| MCP:I7emSV |         final String username;
| MCP:I7emSV | 
| MCP:I7emSV |         // if the token is not present or does not start with "Bearer ", skip the filter
| MCP:I7emSV |         if (authHeader == null ||!authHeader.startsWith("Bearer ")) {
| MCP:I7emSV |             filterChain.doFilter(request, response);
| MCP:I7emSV |             return;
| MCP:I7emSV |         }
| MCP:I7emSV | 
| MCP:I7emSV |         // extract the token from the header
| MCP:I7emSV |         jwt = authHeader.substring(7);
| MCP:I7emSV | 
| MCP:I7emSV |         // extract the username from the token
| MCP:I7emSV |         username = jwtService.extractUsername(jwt);
| MCP:I7emSV | 
| MCP:I7emSV |         // if the username is not null and the authentication context is null, authenticate the user
| MCP:I7emSV |         if (username != null && SecurityContextHolder.getContext().getAuthentication() == null) {
| MCP:I7emSV |             // load the user details from the database
| MCP:I7emSV |             UserDetails userDetails = this.userDetailsService.loadUserByUsername(username);
| MCP:I7emSV | 
| MCP:I7emSV |             // check if the token is valid and not revoked
| MCP:I7emSV |             var isTokenValid = tokenRepository.findByToken(jwt)
| MCP:I7emSV |                     .map(t -> !t.isExpired() && !t.isRevoked())
| MCP:I7emSV |                     .orElse(false);
| MCP:I7emSV | 
| MCP:I7emSV |             // if the token is valid, set the authentication context
| MCP:I7emSV |             if (jwtService.isTokenValid(jwt, userDetails) && isTokenValid) {
| MCP:I7emSV |                 // create the authentication token
| MCP:I7emSV |                 UsernamePasswordAuthenticationToken authToken = new UsernamePasswordAuthenticationToken(
| MCP:I7emSV |                         userDetails,
| MCP:I7emSV |                         null,
| MCP:I7emSV |                         userDetails.getAuthorities()
| MCP:I7emSV |                 );
| MCP:I7emSV | 
| MCP:I7emSV |                 // set the authentication details
| MCP:I7emSV |                 authToken.setDetails(
| MCP:I7emSV |                         new WebAuthenticationDetailsSource().buildDetails(request)
| MCP:I7emSV |                 );
| MCP:I7emSV | 
| MCP:I7emSV |                 // set the authentication context
| MCP:I7emSV |                 SecurityContextHolder.getContext().setAuthentication(authToken);
| MCP:I7emSV |             }
| MCP:I7emSV |         }
| MCP:I7emSV | 
| MCP:I7emSV |         // continue the filter chain
| MCP:I7emSV |         filterChain.doFilter(request, response);
| MCP:I7emSV |     }
| MCP:I7emSV | }

