| MCP:I7emSV |      */
| MCP:I7emSV |     private SecretKey getSignInKey() {
| MCP:I7emSV |         byte[] keyBytes = Decoders.BASE64.decode(secretKey);
| MCP:I7emSV |         return Keys.hmacShaKeyFor(keyBytes);
| MCP:I7emSV |     }
| MCP:I7emSV | }

