| MCP:I7emSV | import jakarta.servlet.http.HttpServletResponse;
| MCP:I7emSV | import lombok.RequiredArgsConstructor;
| MCP:I7emSV | import org.springframework.beans.factory.annotation.Value;
| MCP:I7emSV | import org.springframework.http.HttpHeaders;
| MCP:I7emSV | import org.springframework.security.authentication.AuthenticationManager;
| MCP:I7emSV | import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
| MCP:I7emSV | import org.springframework.security.crypto.password.PasswordEncoder;
| MCP:I7emSV | import org.springframework.stereotype.Service;
| MCP:I7emSV | 
| MCP:I7emSV | import java.time.LocalDateTime;
| MCP:I7emSV | import java.util.List;
| MCP:I7emSV | 
| MCP:I7emSV | /**
| MCP:I7emSV |  * Authentication service for login and register
| MCP:I7emSV |  *
| MCP:I7emSV |  * @author tzesh
| MCP:I7emSV |  * @see AuthenticationService
| MCP:I7emSV |  * @see AuthenticationManager
| MCP:I7emSV |  * @see PasswordEncoder
| MCP:I7emSV |  * @see JwtService
| MCP:I7emSV |  * @see UserRepository
| MCP:I7emSV |  * @see TokenRepository
| MCP:I7emSV |  */
| MCP:I7emSV | @Service
| MCP:I7emSV | @RequiredArgsConstructor
| MCP:I7emSV | public class AuthenticationService {
| MCP:I7emSV |     @Value("${security.jwt.authorization-key}")
| MCP:I7emSV |     private String authorizationKey;
| MCP:I7emSV |     private final UserRepository repository;
| MCP:I7emSV |     private final TokenRepository tokenRepository;
| MCP:I7emSV |     private final PasswordEncoder passwordEncoder;
| MCP:I7emSV |     private final JwtService jwtService;
| MCP:I7emSV |     private final AuthenticationManager authenticationManager;
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Register user
| MCP:I7emSV |      *
| MCP:I7emSV |      * @param request Register request
| MCP:I7emSV |      * @return AuthenticationResponse
| MCP:I7emSV |      * @throws RuntimeException if username or email already exists
| MCP:I7emSV |      * @see RegisterRequest
| MCP:I7emSV |      */
| MCP:I7emSV |     public AuthenticationResponse register(final RegisterRequest request) {
| MCP:I7emSV |         if (repository.existsByUsernameOrEmail(request.username(), request.email())) {
| MCP:I7emSV |             throw new BaseException(
| MCP:I7emSV |                     GenericErrorMessage.builder()
| MCP:I7emSV |                             .message("Username or email already exists")
| MCP:I7emSV |                             .build()
| MCP:I7emSV |             );
| MCP:I7emSV |         }
| MCP:I7emSV | 
| MCP:I7emSV |         final User user = User.builder()
| MCP:I7emSV |                 .username(request.username())
| MCP:I7emSV |                 .email(request.email())
| MCP:I7emSV |                 .name(request.name())
| MCP:I7emSV |                 .password(passwordEncoder.encode(request.password()))
| MCP:I7emSV |                 .role(Role.USER)
| MCP:I7emSV |                 .build();
| MCP:I7emSV |         final BaseAuditableFields auditableFields = new BaseAuditableFields();
| MCP:I7emSV |         auditableFields.setCreatedBy(user.getUsername());
| MCP:I7emSV |         auditableFields.setCreatedDate(LocalDateTime.now());
| MCP:I7emSV |         user.setAuditableFields(auditableFields);
| MCP:I7emSV | 
| MCP:I7emSV |         final User savedUser = repository.save(user);
| MCP:I7emSV |         final String jwtToken = jwtService.generateToken(user);
| MCP:I7emSV |         final String refreshToken = jwtService.generateRefreshToken(user);
| MCP:I7emSV | 
| MCP:I7emSV |         saveUserToken(savedUser, jwtToken);
| MCP:I7emSV | 
| MCP:I7emSV |         return AuthenticationResponse.builder()
| MCP:I7emSV |                 .accessToken(jwtToken)
| MCP:I7emSV |                 .refreshToken(refreshToken)
| MCP:I7emSV |                 .build();
| MCP:I7emSV |     }
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Login user
| MCP:I7emSV |      *
| MCP:I7emSV |      * @param request Login request
| MCP:I7emSV |      * @return AuthenticationResponse
| MCP:I7emSV |      * @see LoginRequest
| MCP:I7emSV |      */
| MCP:I7emSV |     public AuthenticationResponse login(final LoginRequest request) {
| MCP:I7emSV |         authenticationManager.authenticate(
| MCP:I7emSV |                 new UsernamePasswordAuthenticationToken(
| MCP:I7emSV |                         request.username(),
| MCP:I7emSV |                         request.password()
| MCP:I7emSV |                 )
| MCP:I7emSV |         );
| MCP:I7emSV | 
| MCP:I7emSV |         final User user = repository.findByUsername(request.username())
| MCP:I7emSV |                 .orElseThrow(
| MCP:I7emSV |                         () -> new NotFoundException(
| MCP:I7emSV |                                 GenericErrorMessage.builder()
| MCP:I7emSV |                                         .message("User not found with username: " + request.username())
| MCP:I7emSV |                                         .build()
| MCP:I7emSV |                         )
| MCP:I7emSV |                 );
| MCP:I7emSV | 
| MCP:I7emSV |         final String jwtToken = jwtService.generateToken(user);
| MCP:I7emSV |         final String refreshToken = jwtService.generateRefreshToken(user);
| MCP:I7emSV |         revokeAllUserTokens(user);
| MCP:I7emSV |         saveUserToken(user, jwtToken);
| MCP:I7emSV |         return AuthenticationResponse.builder()
| MCP:I7emSV |                 .accessToken(jwtToken)
| MCP:I7emSV |                 .refreshToken(refreshToken)
| MCP:I7emSV |                 .build();
| MCP:I7emSV |     }
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Save user token
| MCP:I7emSV |      *
| MCP:I7emSV |      * @param user     User
| MCP:I7emSV |      * @param jwtToken JWT token
| MCP:I7emSV |      */
| MCP:I7emSV |     private void saveUserToken(final User user, final String jwtToken) {
| MCP:I7emSV |         final TokenEntity tokenEntity = TokenEntity.builder()
| MCP:I7emSV |                 .user(user)
| MCP:I7emSV |                 .token(jwtToken)
| MCP:I7emSV |                 .expired(false)
| MCP:I7emSV |                 .revoked(false)
| MCP:I7emSV |                 .build();
| MCP:I7emSV |         tokenRepository.save(tokenEntity);
| MCP:I7emSV |     }
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Revoke all user tokens
| MCP:I7emSV |      *
| MCP:I7emSV |      * @param user User
| MCP:I7emSV |      */
| MCP:I7emSV |     private void revokeAllUserTokens(final User user) {
| MCP:I7emSV |         final List<TokenEntity> validUserTokenEntities = tokenRepository.findAllValidTokenByUser(user.getId());
| MCP:I7emSV |         if (validUserTokenEntities.isEmpty())
| MCP:I7emSV |             return;
| MCP:I7emSV |         validUserTokenEntities.forEach(tokenEntity -> {
| MCP:I7emSV |             tokenEntity.setExpired(true);
| MCP:I7emSV |             tokenEntity.setRevoked(true);
| MCP:I7emSV |         });
| MCP:I7emSV |         tokenRepository.saveAll(validUserTokenEntities);
| MCP:I7emSV |     }
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Refresh token
| MCP:I7emSV |      *
| MCP:I7emSV |      * @param request  HTTP request
| MCP:I7emSV |      * @param response HTTP response
| MCP:I7emSV |      */
| MCP:I7emSV |     public AuthenticationResponse refreshToken(final HttpServletRequest request, final HttpServletResponse response) {
| MCP:I7emSV |         final String authHeader = request.getHeader(HttpHeaders.AUTHORIZATION);
| MCP:I7emSV |         final String refreshToken;
| MCP:I7emSV |         final String username;
| MCP:I7emSV |         if (authHeader == null || !authHeader.startsWith("Bearer ")) {
| MCP:I7emSV |             return null;
| MCP:I7emSV |         }
| MCP:I7emSV |         refreshToken = authHeader.substring(7);
| MCP:I7emSV |         username = jwtService.extractUsername(refreshToken);
| MCP:I7emSV |         if (username != null) {
| MCP:I7emSV |             final User user = this.repository.findByUsername(username)
| MCP:I7emSV |                     .orElseThrow(
| MCP:I7emSV |                             () -> new NotFoundException(
| MCP:I7emSV |                                     GenericErrorMessage.builder()
| MCP:I7emSV |                                             .message("User not found with username: " + username)
| MCP:I7emSV |                                             .build()
| MCP:I7emSV |                             )
| MCP:I7emSV |                     );
| MCP:I7emSV |             if (jwtService.isTokenValid(refreshToken, user)) {
| MCP:I7emSV |                 final String accessToken = jwtService.generateToken(user);
| MCP:I7emSV |                 revokeAllUserTokens(user);
| MCP:I7emSV |                 saveUserToken(user, accessToken);
| MCP:I7emSV |                 return AuthenticationResponse.builder()
| MCP:I7emSV |                         .accessToken(accessToken)
| MCP:I7emSV |                         .refreshToken(refreshToken)
| MCP:I7emSV |                         .build();
| MCP:I7emSV |             }
| MCP:I7emSV |         }
| MCP:I7emSV |         return null;
| MCP:I7emSV |     }
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Authorize user to the role
| MCP:I7emSV |      *
| MCP:I7emSV |      * @param request Authorization request
| MCP:I7emSV |      * @return AuthenticationResponse
| MCP:I7emSV |      * @see AuthorizationRequest
| MCP:I7emSV |      * @see AuthenticationResponse
| MCP:I7emSV |      */
| MCP:I7emSV |     public AuthenticationResponse authorize(final AuthorizationRequest request) {
| MCP:I7emSV |         if (!request.secret().equals(authorizationKey)) {
| MCP:I7emSV |             throw new RuntimeException("Secret is not correct");
| MCP:I7emSV |         }
| MCP:I7emSV | 
| MCP:I7emSV |         final User user = repository.findByUsername(request.username())
| MCP:I7emSV |                 .orElseThrow(
| MCP:I7emSV |                         () -> new NotFoundException(
| MCP:I7emSV |                                 GenericErrorMessage.builder()
| MCP:I7emSV |                                         .message("User not found with username: " + request.username())
| MCP:I7emSV |                                         .build()
| MCP:I7emSV |                         )
| MCP:I7emSV |                 );
| MCP:I7emSV |         user.setRole(request.role());
| MCP:I7emSV | 
| MCP:I7emSV |         final BaseAuditableFields auditableFields = user.getAuditableFields();
| MCP:I7emSV |         auditableFields.setUpdatedBy("SYSTEM");
| MCP:I7emSV |         auditableFields.setUpdatedDate(LocalDateTime.now());
| MCP:I7emSV | 
| MCP:I7emSV |         final User updatedUser = repository.save(user);
| MCP:I7emSV |         final String jwtToken = jwtService.generateToken(updatedUser);
| MCP:I7emSV |         final String refreshToken = jwtService.generateRefreshToken(updatedUser);
| MCP:I7emSV |         saveUserToken(updatedUser, jwtToken);
| MCP:I7emSV |         return AuthenticationResponse.builder()
| MCP:I7emSV |                 .accessToken(jwtToken)
| MCP:I7emSV |                 .refreshToken(refreshToken)
| MCP:I7emSV |                 .build();
| MCP:I7emSV |     }
| MCP:I7emSV | 
| MCP:I7emSV | }

