| MCP:I7emSV | import lombok.extern.slf4j.Slf4j;
| MCP:I7emSV | import org.springframework.http.HttpStatus;
| MCP:I7emSV | import org.springframework.security.core.AuthenticationException;
| MCP:I7emSV | import org.springframework.stereotype.Component;
| MCP:I7emSV | 
| MCP:I7emSV | import java.io.IOException;
| MCP:I7emSV | 
| MCP:I7emSV | /**
