| MCP:I7emSV | 
| MCP:I7emSV |         // set response content type
| MCP:I7emSV |         response.setContentType("application/json");
| MCP:I7emSV | 
| MCP:I7emSV |         // create error message
| MCP:I7emSV |         GenericErrorMessage genericErrorMessage = GenericErrorMessage.builder()
