| MCP:I7emSV | 
| MCP:I7emSV |         // write response
| MCP:I7emSV |         response.getWriter().write(
| MCP:I7emSV |                 Json.pretty(
| MCP:I7emSV |                         BaseResponse.builder()
| MCP:I7emSV |                                 .status(HttpStatus.UNAUTHORIZED)
| MCP:I7emSV |                                 .data(
| MCP:I7emSV |                                         genericErrorMessage
| MCP:I7emSV |                                 )
| MCP:I7emSV |                                 .message("Unauthorized to access this resource")
| MCP:I7emSV |                                 .build()
| MCP:I7emSV |                 )
| MCP:I7emSV |         );
| MCP:I7emSV | 
| MCP:I7emSV |         // log error
