| MCP:I7emSV | 
| MCP:I7emSV |         // flush writer
| MCP:I7emSV |         response.getWriter().flush();
| MCP:I7emSV | 
| MCP:I7emSV |         // close writer
| MCP:I7emSV |         response.getWriter().close();
| MCP:I7emSV |     }
| MCP:I7emSV | }

