| MCP:I7emSV | import org.springframework.stereotype.Service;
| MCP:I7emSV | 
| MCP:I7emSV | /**
| MCP:I7emSV |  * Logout service to revoke token
| MCP:I7emSV |  *
| MCP:I7emSV |  * @author tzesh
| MCP:I7emSV |  * @see LogoutHandler
| MCP:I7emSV |  * @see TokenRepository
| MCP:I7emSV |  */
| MCP:I7emSV | @Service
| MCP:I7emSV | @RequiredArgsConstructor
| MCP:I7emSV | public class LogoutService implements LogoutHandler {
| MCP:I7emSV | 
| MCP:I7emSV |     private final TokenRepository tokenRepository;
| MCP:I7emSV | 
| MCP:I7emSV |     /**
| MCP:I7emSV |      * Revoke token
| MCP:I7emSV |      *
| MCP:I7emSV |      * @param request        Request
| MCP:I7emSV |      * @param response       Response
| MCP:I7emSV |      * @param authentication Authentication
| MCP:I7emSV |      */
| MCP:I7emSV |     @Override
| MCP:I7emSV |     public void logout(
| MCP:I7emSV |             final HttpServletRequest request,
| MCP:I7emSV |             final HttpServletResponse response,
| MCP:I7emSV |             final Authentication authentication) {
| MCP:I7emSV |         final String authHeader = request.getHeader("Authorization");
| MCP:I7emSV |         final String jwt;
| MCP:I7emSV | 
| MCP:I7emSV |         if (authHeader == null || !authHeader.startsWith("Bearer ")) {
| MCP:I7emSV |             return;
| MCP:I7emSV |         }
| MCP:I7emSV | 
| MCP:I7emSV |         jwt = authHeader.substring(7);
| MCP:I7emSV | 
| MCP:I7emSV |         final var storedToken = tokenRepository.findByToken(jwt)
| MCP:I7emSV |                 .orElse(null);
| MCP:I7emSV | 
| MCP:I7emSV |         if (storedToken != null) {
| MCP:I7emSV |             storedToken.setExpired(true);
| MCP:I7emSV |             storedToken.setRevoked(true);
| MCP:I7emSV | 
| MCP:I7emSV |             tokenRepository.save(storedToken);
| MCP:I7emSV | 
| MCP:I7emSV |             SecurityContextHolder.clearContext();
| MCP:I7emSV |         }
| MCP:I7emSV |     }
| MCP:I7emSV | }
